import React, { type ReactElement, Fragment, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { Global } from '@emotion/react';
import { Text } from '@arwes/react-text'
import {
  type ThemeSettingsUnit,
  type ThemeSettingsMultiplier,
  type ThemeSettingsColor,
  type ThemeSettingsStyle,
  type ThemeUnit,
  type ThemeMultiplier,
  type ThemeColor,
  type ThemeStyle,
  type ThemeCreatorStructure,
  createCreateTheme
} from '@arwes/theme';

interface ThemeSettings {
  space: ThemeSettingsUnit,
  outline: ThemeSettingsMultiplier,
  font: ThemeSettingsStyle,
  color: {
    primary: ThemeSettingsColor,
    secondary: ThemeSettingsColor
  }
}

interface Theme {
  space: ThemeUnit,
  outline: ThemeMultiplier,
  font: ThemeStyle,
  color: {
    primary: ThemeColor,
    secondary: ThemeColor
  }
}

const themeStructure: ThemeCreatorStructure = {
  space: 'multiplier',
  outline: 'multiplier',
  font: 'style',
  color: {
    primary: 'color',
    secondary: 'color'
  }
};

const themeDefaults: ThemeSettings = {
  // Values to be multiplied by a provided integer.
  space: i => `${i}rem`,
  outline: 1,
  // A list of styles with any CSS properties.
  font: [
    { fontFamily: 'monospace', fontSize: '30px' },
    { fontFamily: 'sans-serif', fontSize: '21px' },
    { fontFamily: 'Titillium Web', fontSize: '18px' },
    { fontFamily: 'Tomorrow', fontSize: '16px' }
  ],
  color: {
    // A function to return a HSLA value as [number, number, number, number?].
    primary: i => [180, 70, i * 5, 1],
    secondary: i => [60, 70, i * 5, 1]
  }
};

const createTheme = createCreateTheme(themeStructure, themeDefaults);

const Sandbox = (): ReactElement => {
  const theme: Theme = useMemo(() => {
    const themeExtensions = {
      outline: 3
    };
    const theme = createTheme(themeExtensions);
    return theme;
  }, []);

  return (
    <Fragment>
      <Global styles={{
        html: {
          margin: theme.space(2),
          backgroundColor: theme.color.primary(1)
        },
        h1: {
          ...theme.font(0),
          marginBottom: theme.space(1),
          borderBottomWidth: theme.outline(1),
          borderBottomStyle: 'solid',
          borderBottomColor: theme.color.primary(10),
          paddingBottom: theme.space(1),
          color: theme.color.primary(16)
        },
        h2: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        h3: {
          ...theme.font(2),
          color: theme.color.primary(16)
        },
        h4: {
          ...theme.font(3),
          color: theme.color.secondary(16)
        },
        h5: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        h6: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        p: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        ul: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        li: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        ol: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        pre: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        blockquote: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        table: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        },
        figcaption: {
          ...theme.font(1),
          color: theme.color.secondary(16)
        }
      }} />
      <h1>h1. Arwes Framework</h1>
      <h2>h2. Futuristic Sci-Fi UI Web Framework</h2>
      <h3>h3. Lorem ipsum lov sit amet</h3>
    <h4>h4. Lorem ipsum lov sit amet</h4>
    <h5>h5. Lorem ipsum lov sit amet</h5>
    <h6>h6. Lorem ipsum lov sit amet</h6>
    <hr />
    <p>
      p. Lorem ipsum lov sit amet, consectetur adipiscing elit, sed
